// Robot Buddy — a friendly retro desktop robot.
// BREP showcase: cone head, torus collar, cylindrical arms + antenna,
// box torso, box feet. Each feature labeled for paintByLabel.
const { BREP } = api;

// ---- Feet (two squat boxes under the torso) ----
// box([w,d,h]) is XY-centred with base at z=0, so we offset in X to split
// them left/right, and leave z at 0 so the robot sits on the ground.
const footW = 7, footD = 9, footH = 5;
const footL = BREP.box([footW, footD, footH]).translate([-7, 0, 0]);
const footR = BREP.box([footW, footD, footH]).translate([+7, 0, 0]);
const feet = BREP.label(BREP.fuseAll([footL, footR]), 'foot');

// ---- Torso (boxy body) ----
// Base of torso sits on top of feet (z = 5).
const torsoW = 25, torsoD = 18, torsoH = 22;
const torsoZ0 = footH; // 5
const torso = BREP.label(
  BREP.box([torsoW, torsoD, torsoH]).translate([0, 0, torsoZ0]),
  'torso',
);

// ---- Arms (stubby horizontal cylinders) ----
// BREP.cylinder is axis-Z by default; rotate 90° around Y to make it horizontal.
// Place at roughly torso mid-height (z ~= torsoZ0 + 14).
const armR = 3, armLen = 8;
const armZ = torsoZ0 + 14;
// Cylinder base at z=0 along +Z; rotate -90° around Y makes axis +X with base at x=0.
const armProto = BREP.cylinder(armR, armLen);
const armRight = armProto.rotate(-90, [0, 1, 0]).translate([torsoW / 2, 0, armZ]);
const armLeft = armProto.rotate(+90, [0, 1, 0]).translate([-torsoW / 2, 0, armZ]);
const arms = BREP.label(BREP.fuseAll([armLeft, armRight]), 'arm');

// ---- Collar (torus around the head/torso joint) ----
// Sits at the top of the torso (z = torsoZ0 + torsoH = 27).
const collarZ = torsoZ0 + torsoH; // 27
const collar = BREP.label(
  BREP.torus(11, 1.5).translate([0, 0, collarZ]),
  'collar',
);

// ---- Head (truncated cone — wider at bottom, narrower at top) ----
const headRBottom = 13, headRTop = 9, headH = 10;
const headZ0 = collarZ; // 27
const head = BREP.label(
  BREP.cone(headRBottom, headRTop, headH).translate([0, 0, headZ0]),
  'head',
);

// ---- Eyes (two small cylinders embedded in the head's front face) ----
// Front face of head = +Y side. Cylinders pointing in -Y (into the head)
// so they read as inset lenses after fusing.
// Eye centre at roughly mid-head height + slightly forward of the cone wall.
const eyeR = 2.5, eyeLen = 2;
const eyeZ = headZ0 + headH / 2; // 32
// At z=eyeZ, head radius (linear interp): rBottom + (rTop-rBottom)*(eyeZ-headZ0)/headH
// = 13 + (9-13)*0.5 = 11. So front of head is around y=+11 there.
// rotate(-90, [1,0,0]) maps +Z -> +Y, so a base-at-z=0 cylinder becomes
// a base-at-y=0 cylinder pointing in +Y (sticking out the front of the head).
const eyeProto = BREP.cylinder(eyeR, eyeLen).rotate(-90, [1, 0, 0]);
const eyeRight = eyeProto.translate([+4.5, 9.5, eyeZ]);
const eyeLeft = eyeProto.translate([-4.5, 9.5, eyeZ]);
const eyes = BREP.label(BREP.fuseAll([eyeLeft, eyeRight]), 'eye');

// ---- Chest panel (a small box bumped out of the front of the torso) ----
// Centered on the +Y face of the torso. We make it slightly proud so it's
// visible but we'll paint it later by AABB — no separate label needed.
const panelW = 14, panelD = 1.2, panelH = 10;
const panelZ = torsoZ0 + (torsoH - panelH) / 2; // centred vertically on torso
const panel = BREP.box([panelW, panelD, panelH]).translate(
  [0, torsoD / 2, panelZ],
);
// We do NOT label the panel — it will be painted by paintInBox.

// ---- Antenna (thin cylinder topped with a sphere) ----
const antennaR = 0.8, antennaH = 8;
const antennaZ0 = headZ0 + headH; // 37
const antennaRod = BREP.cylinder(antennaR, antennaH).translate([0, 0, antennaZ0]);
const antennaBall = BREP.sphere(1.8).translate([0, 0, antennaZ0 + antennaH + 0.8]);
const antenna = BREP.label(BREP.fuseAll([antennaRod, antennaBall]), 'antenna');

// ---- Assemble ----
return BREP.fuseAll([feet, torso, arms, collar, head, eyes, panel, antenna]);

